search:Angular + Firebase Authentication.content:
- Install Angular CLI: `npm install -g @angular/cli`
- Create new Angular project: `ng new my-angular-app`
- Add Firebase to Angular project:
  ```bash
  ng add @angular/fire
  ```
  Follow prompts to configure Firebase.
- Key config options in `environment.ts`:
  ```typescript
  export const environment = {
    production: false,
    firebase: {
      apiKey: "YOUR_API_KEY",
      authDomain: "YOUR_AUTH_DOMAIN",
      projectId: "YOUR_PROJECT_ID",
      storageBucket: "YOUR_STORAGE_BUCKET",
      messagingSenderId: "YOUR_MESSAGING_SENDER_ID",
      appId: "YOUR_APP_ID"
    }
  };
  ```
- Import Firebase modules in `app.module.ts`:
  ```typescript
  import { AngularFireModule } from '@angular/fire';
  import { AngularFirestoreModule } from '@angular/fire/firestore';
  import { environment } from '../environments/environment';

  @NgModule({
    imports: [
      AngularFireModule.initializeApp(environment.firebase),
      AngularFirestoreModule,
    ],
  })
  export class AppModule {}
  ```
- Register user with Firebase:
  ```typescript
  import { AngularFireAuth } from '@angular/fire/auth';

  constructor(private auth: AngularFireAuth) {}

  registerUser(email: string, password: string) {
    this.auth.createUserWithEmailAndPassword(email, password)
      .then((userCredential) => {
        // Signed in 
        var user = userCredential.user;
        console.log(user);
      })
      .catch((error) => {
        var errorCode = error.code;
        var errorMessage = error.message;
        console.error(errorCode, errorMessage);
      });
  }
  ```
